### 9. ACCESSIBILITY: 6/10
**Problems:**
- Reduced motion preference is implemented but not consistently
- Color contrast ratios are borderline acceptable (4.5:1)
- No ARIA labels for interactive elements
- Keyboard navigation is incomplete
- No skip navigation link

**Specific Fixes:**
```tsx
// Comprehensive accessibility improvements
const AccessibleButton = ({ children, ...props }) => {
  return (
    <motion.button
      {...props}
      aria-label={props.ariaLabel || children}
      whileHover={{ scale: 1.02 }}
      whileTap={{ scale: 0.98 }}
      transition={{ 
        type: "spring", 
        stiffness: 400, 
        damping: 10,
        when: "beforeChildren"
      }}
      className="accessible-button"
    >
      {children}
    </motion.button>
  );
};

// Skip navigation link
const SkipLink = () => {
  return (
    <a 
      href="#main-content" 
      className="skip-link"
      onFocus={(e) => e.target.classList.add('focus-visible')}
    >
      Перейти к основному содержанию
    </a>
  );
};

// Improved color contrast
const AccessibleText = ({ children, variant = 'body', ...props }) => {
  const colorStyles = {
    body: { color: '#1a1a1a', backgroundColor: '#ffffff' },
    heading: { color: '#000000', backgroundColor: '#ffffff' },
    accent: { color: '#C8782A', backgroundColor: '#ffffff' }
  };

  return (
    <p 
      className={`text ${variant}`} 
      style={colorStyles[variant]}
      {...props}
    >
      {children}
    </p>
  );
};
```

### 10. PERFORMANCE: 7/10
**Problems:**
- Hero video isn't properly lazy-loaded
- Large bundle size due to Framer Motion implementation
- No preloading of critical resources
- Cart state causes unnecessary re-renders
- Images aren't optimized for different viewports

**Specific Fixes:**
```tsx
// Optimized video loading
const OptimizedHeroVideo = () => {
  const [videoLoaded, setVideoLoaded] = useState(false);

  return (
    <div className="hero-video-container">
      <video 
        className="hero-video"
        playsInline
        muted
        loop
        autoPlay
        onLoad={() => setVideoLoaded(true)}
        poster="/hero-poster.jpg"
      >
        <source src="/hero-video.mp4" type="video/mp4" />
        <track kind="captions" srcLang="ru" label="Russian" />
      </video>
      {!videoLoaded && <VideoPlaceholder />}
    </div>
  );
};

// Image optimization
const OptimizedImage = ({ src, alt, ...props }) => {
  const [isLoaded, setIsLoaded] = useState(false);

  return (
    <div className="image-container">
      <img
        src={src}
        alt={alt}
        onLoad={() => setIsLoaded(true)}
        className={`image ${isLoaded ? 'loaded' : 'loading'}`}
        {...props}
      />
      {!isLoaded && <ImagePlaceholder />}
    </div>
  );
};

// Cart state optimization
const OptimizedCartProvider = ({ children }) => {
  const [cart, setCart] = useLocalStorage('cateringCart', []);
  const [cartVersion, setCartVersion] = useState(0);

  const addItem = useCallback((item) => {
    setCart(prev => [...prev, item]);
    setCartVersion(v => v + 1);
  }, [setCart]);

  const removeItem = useCallback((id) => {
    setCart(prev => prev.filter(item => item.id !== id));
    setCartVersion(v => v + 1);
  }, [setCart]);

  return (
    <CartContext.Provider value={{ cart, addItem, removeItem, cartVersion }}>
      {children}
    </CartContext.Provider>
  );
};
```

